from openai_agents import Agent
import json

class ConsistentAgent(Agent):
    MAX_RETRIES = 3

    def run_with_consistency(self, input):
        for attempt in range(self.MAX_RETRIES):
            result = self.run(input)
            try:
                # Validate exact format
                json.loads(result.output)
                if 'action' in result.output and 'params' in result.output:
                    return result
            except:
                pass
        raise ValueError('Could not produce consistent output')

agent = ConsistentAgent(name='reliable-agent')

from openai_agents import Workflow, Agent

from pydantic import BaseModel

class HandoffPayload(BaseModel):
    context: str
    intent: str
    data: dict

class NormalizedWorkflow(Workflow):
    def process_handoff(self, from_agent, to_agent, output):
        normalized = HandoffPayload(
            context=output.context,
            intent=output.intent,
            data=output.data
        )
        to_agent.inputs = [normalized.model_dump_json()]
        return super().process_handoff(from_agent, to_agent, output)

